repo_files.flags.py:
_TRUE_VALUES = {"1", "true", "yes", "on"}


def enabled(env: dict[str, str], name: str) -> bool:
    return bool(env.get(name, "0"))

repo_files.worker_mode.py:
from flags import enabled


def resolved_mode(env: dict[str, str]) -> str:
    if env.get("CHILI_EXPERIMENTAL_GATE"):
        return "experimental"
    return "stable"

repo_files.tests/test_public.py:
from flags import enabled
from worker_mode import resolved_mode


def test_explicit_one_uses_experimental_mode():
    env = {"CHILI_EXPERIMENTAL_GATE": "1"}
    assert enabled(env, "CHILI_EXPERIMENTAL_GATE") is True
    assert resolved_mode(env) == "experimental"
